import java.util.ArrayList;
import java.util.List;

public class Main {
    static void permute(int[] nums, List<Integer> current, boolean[] used, List<List<Integer>> result) {
        if (current.size() == nums.length) {
            result.add(new ArrayList<>(current));
            return;
        }

        for (int i = 0; i < nums.length; i++) {
            if (used[i]) {
                continue;
            }

            current.add(nums[i]);   // CHOOSE
            used[i] = true;

            permute(nums, current, used, result); // EXPLORE

            current.remove(current.size() - 1); // UNCHOOSE
            used[i] = false;
        }
    }

    public static void main(String[] args) {
        int[] nums = {1, 2, 3};
        List<List<Integer>> result = new ArrayList<>();
        permute(nums, new ArrayList<>(), new boolean[nums.length], result);
        System.out.println(result.size());
        System.out.println(result);
    }
}

import java.util.ArrayList;
import java.util.List;

public class Main {
    static void combinationSum(int[] candidates, int target, int start, List<Integer> current, List<List<Integer>> result) {
        if (target == 0) {
            result.add(new ArrayList<>(current));
            return;
        }
        if (target < 0) {
            return; // PRUNE -- this path can never work, stop exploring it
        }

        for (int i = start; i < candidates.length; i++) {
            current.add(candidates[i]);
            combinationSum(candidates, target - candidates[i], i, current, result);
            current.remove(current.size() - 1);
        }
    }

    public static void main(String[] args) {
        int[] candidates = {2, 3, 5};
        List<List<Integer>> result = new ArrayList<>();
        combinationSum(candidates, 7, 0, new ArrayList<>(), result);
        System.out.println(result);
    }
}

